import React, { useState, useEffect, useRef } from 'react'
import {
  CCardHeader,
  CButton,
  CCard,
  CCardBody,
  CRow,
  CCol,
  CFormInput,
  CFormFloating,
  CFormLabel,
  CForm,
  CSpinner,
  CToaster,
} from '@coreui/react'
import { getUser } from 'src/utils/Auth'
import axios from 'axios'
import Notify from 'src/utils/Notify'

const AppForm = () => {
  const [validated, setValidated] = useState(false)
  const [message, setMessage] = useState(null)
  const [error, setError] = useState(false)
  const [toast, addToast] = useState(0)
  const toaster = useRef()
  const [resetPassword, setResetPassword] = useState({})

  useEffect(() => {
    if (message) addToast(notify)
  }, [message])

  const user = getUser()
  const notify = <Notify error={error} message={message} />

  const handleFormChange = (e) => {
    const { id, value } = e.target
    setResetPassword((prevState) => ({
      ...prevState,
      [id]: value,
    }))
  }

  const handleUpdate = () => {
    setMessage(null)
    setMessage('Kindly chat with us to get this resolved, Thank you')
  }

  const handleResetPassword = (e) => {
    e.preventDefault()
    setMessage(null)
    setError(false)
    const form = e.currentTarget
    if (form.checkValidity() === false) {
      e.stopPropagation()
      return
    }
    setValidated(true)
    axios
      .post('https://records.run.edu.ng/api/app/reset_password', {
        email: user.email,
        old_pass: resetPassword.old_pass,
        password: resetPassword.password,
        password_confirmation: resetPassword.password_confirmation,
      })
      .then((res) => {
        setError(false)
        setMessage(res.data.message)
        setValidated(false)
      })
      .catch((err) => {
        setError(true)
        setValidated(false)
        if (err.response) {
          console.log(err.response)
          setMessage(err.response.data.message)
        } else {
          setMessage('Network Error!')
        }
      })
  }
  return (
    <>
      <CCard className="mb-4">
        <CCardHeader>Account Settings</CCardHeader>
        <CCardBody>
          <CRow className="g-3">
            <CCol xs>
              <CFormFloating className="mb-3">
                <CFormInput
                  readOnly
                  defaultValue={user.surname + ' ' + user.firstname}
                  id="fullname"
                />
                <CFormLabel htmlFor="fullname">Fullname</CFormLabel>
              </CFormFloating>
            </CCol>
            <CCol xs>
              <CFormFloating className="mb-3">
                <CFormInput type="email" defaultValue={user.email} id="email" readOnly />
                <CFormLabel htmlFor="email">Email</CFormLabel>
              </CFormFloating>
            </CCol>
          </CRow>
          <div className="d-grid">
            <CButton
              shape="rounded-pill"
              variant="outline"
              color="warning"
              onClick={() => handleUpdate()}
            >
              Request Update
            </CButton>
          </div>
        </CCardBody>
      </CCard>

      <CCard className="mb-4">
        <CCardHeader>Reset Password</CCardHeader>
        <CCardBody>
          <CForm noValidate validated={validated} onSubmit={handleResetPassword}>
            <CRow className="g-3">
              <CCol xs>
                <CFormFloating className="mb-3">
                  <CFormInput type="password" id="old_pass" onChange={handleFormChange} required />
                  <CFormLabel htmlFor="old_pass">Current Password</CFormLabel>
                </CFormFloating>
              </CCol>
              <CCol xs>
                <CFormFloating className="mb-3">
                  <CFormInput type="password" id="password" onChange={handleFormChange} required />
                  <CFormLabel htmlFor="password">New Password</CFormLabel>
                </CFormFloating>
              </CCol>
              <CCol xs>
                <CFormFloating className="mb-3">
                  <CFormInput
                    type="password"
                    id="password_confirmation"
                    onChange={handleFormChange}
                    required
                  />
                  <CFormLabel htmlFor="password_confirmation">Confirm Password</CFormLabel>
                </CFormFloating>
              </CCol>
            </CRow>
            <div className="d-grid">
              <CButton
                shape="rounded-pill"
                disabled={validated}
                type="submit"
                variant="outline"
                color="warning"
              >
                {validated && (
                  <CSpinner
                    component="span"
                    size="sm"
                    color="warning"
                    variant="grow"
                    aria-hidden="true"
                  />
                )}{' '}
                Reset password
              </CButton>
            </div>
          </CForm>
        </CCardBody>
      </CCard>
      <CToaster ref={toaster} push={toast} placement="top-end" />
    </>
  )
}

export default AppForm
